 "arch.kicker": "Arsitektur",
 "arch.title": "Sebuah percetakan berisi <span class=\"accent\">modul yang bisa disusun</span>",
 "arch.sub": "Setiap modul menangani satu urusan di balik batas yang tegas, mula-mula dipakai in-process dan dirancang agar bisa dipindah ke balik HTTP atau gRPC tanpa menulis ulang logika bisnis. Bersama-sama, semuanya membentuk platform agent yang utuh.",
 "arch.mods.tag": "Modul-Modul",
 "arch.mods.h2": "Enam belas komponen, ditata di balik batasnya masing-masing",
 "arch.mods.p": "Nama modul mengikuti filosofi percetakan Jikji — masing-masing menyiapkan, mengizinkan, menyusun, mencetak, atau menyebarkan pengetahuan.",
 "g.forme": "forme terkunci",
 "m.forme": "Agent loop deterministik — delegasi, HITL, hook Lua, checkpoint, event per langkah.",
 "g.trinity": "tiga juri",
 "m.trinity": "Koordinator multi-model adaptif — debat swarm, verify-revise, routing hasil evolusi.",
 "g.compositor": "penata huruf",
 "m.compositor": "Orkestrasi sesi, antrean, penyusunan alur, dan memori kolaborasi.",
 "g.dispatch": "pengaturan kerja",
